class IndentationRuleIsExpressionTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a multiline IS_EXPRESSION then indent the right hand side`() {
        val code =
            """
            fun foo(any: Any) =
